fn main() {
    let pair = (2, -2);

    match pair {
        (x, y) if x == y => println!("Equal"),
        (x, _) if x % 2 == 0 => println!("x is even"),
        (_, y) if y < 0 => println!("y is negative"),
        _ => println!("No match"),
    }

    // @ binding
    let number = 5;
    match number {
        n @ 1..=10 => println!("n is between 1 and 10: {}", n),
        _ => println!("Other"),
    }
}
